arguments.file_text:
@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    @if (entry.Error is not null)
                    {
                        <span class="error-message">@entry.Info.Name &mdash; @entry.Error</span>
                    }
                    else
                    {
                        <span class="file-name">@entry.Info.Name</span>
                        <span class="file-meta">@FormatSize(entry.Info.Size) &middot; @entry.Info.Type</span>
                    }
                </div>
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    private record FileEntry(FileInfo Info, string? Error);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-c64d6e9d329145fdb410ba20f6ff6152/Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragEnter() { _isDragOver = true; StateHasChanged(); }

    [JSInvokable]
    public void OnDragLeave() { _isDragOver = false; StateHasChanged(); }

    [JSInvokable]
    public async Task OnFilesDropped(List<FileInfo> droppedFiles)
    {
        _isDragOver = false;

        foreach (var file in droppedFiles)
        {
            string? error = file.Size > MaxFileSize
                ? $"File exceeds 10 MB limit ({FormatSize(file.Size)})"
                : null;
            _files.Add(new FileEntry(file, error));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => f.Error is null)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose");
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    color: #6c757d;
    font-size: 1.1rem;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    min-width: 0;
}

.file-name {
    font-weight: 500;
    word-break: break-all;
}

.file-meta {
    font-size: 0.85rem;
    color: #6c757d;
}

.error-message {
    color: #dc3545;
    font-weight: 500;
    word-break: break-all;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.6rem;
    cursor: pointer;
    flex-shrink: 0;
    margin-left: 1rem;
    font-size: 0.85rem;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

let dropZone, dotNetRef, dragCounter;

export function initDropZone(element, ref) {
    dropZone = element;
    dotNetRef = ref;
    dragCounter = 0;

    dropZone.addEventListener("dragenter", onDragEnter);
    dropZone.addEventListener("dragleave", onDragLeave);
    dropZone.addEventListener("dragover", onDragOver);
    dropZone.addEventListener("drop", onDrop);
}

function onDragEnter(e) {
    e.preventDefault();
    dragCounter++;
    if (dragCounter === 1) {
        dotNetRef.invokeMethodAsync("OnDragEnter");
    }
}

function onDragLeave(e) {
    e.preventDefault();
    dragCounter--;
    if (dragCounter === 0) {
        dotNetRef.invokeMethodAsync("OnDragLeave");
    }
}

function onDragOver(e) {
    e.preventDefault();
}

function onDrop(e) {
    e.preventDefault();
    dragCounter = 0;

    const files = [];
    for (const file of e.dataTransfer.files) {
        files.push({ name: file.name, size: file.size, type: file.type || "application/octet-stream" });
    }

    if (files.length > 0) {
        dotNetRef.invokeMethodAsync("OnFilesDropped", files);
    }
}

export function dispose() {
    if (dropZone) {
        dropZone.removeEventListener("dragenter", onDragEnter);
        dropZone.removeEventListener("dragleave", onDragLeave);
        dropZone.removeEventListener("dragover", onDragOver);
        dropZone.removeEventListener("drop", onDrop);
    }
}

